import React, { useState, useEffect } from 'react';
import useUserAvatar from './useUserAvatar.js';

const App = () => {
  const [channels, setChannels] = useState([]);
  const [currentChannel, setCurrentChannel] = useState(null);
  const [newMessage, setNewMessage] = useState('');
  const [isTypeing, setIsTypeing] = useState(false);

  const { userAvatar } = useUserAvatar();

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="w-1/2 bg-[#090a0f] p-4 shadow-md">
        <div className="flex items-center p-2">
          <img src={userAvatar} alt="User Avatar" className="w-10 h-10 rounded-full"/>
          <input type="text" placeholder="Search" className="bg-transparent p-2 w-full"/>
        </div>
        <div className="p-2">
          <button className="bg-[#B7D7CD] text-[#411C56] p-2 rounded-md">Create Channel</button>
          {channels.map((channel, index) => (
            <button key={index} className="bg-[#C06C88] text-[#411C56] p-2 rounded-md mr-2 mb-2">{channel.name}</button>
          ))}
        </div>
      </div>
      <div className="w-1/2 bg-[#090a0f] p-4 shadow-md">
        <div className="flex items-center p-2">
          <h2 className="text-[#C06C88]">{currentChannel ? currentChannel.name : 'Select a channel'}</h2>
          <button className="bg-[#B7D7CD] text-[#411C56] p-2 rounded-md ml-2">Switch Channel</button>
        </div>
        <div className="p-2">
          <textarea className="bg-transparent p-2 w-full h-20" value={newMessage} onChange={(e) => setNewMessage(e.target.value)} placeholder="Type your message..."/>
          <button className="bg-[#C06C88] text-[#411C56] p-2 rounded-md">Send</button>
          {isTypeing ? <div className="bg-[#C06C88] p-2 rounded-md">Typing...</div> : null}
        </div>
      </div>
    </div>
  );
};

export default App;
